use std::collections::HashMap;

fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut prefix = 0;
    let mut dp = 0;
    let mut mod_map = HashMap::new();
    mod_map.insert(0, 0);

    for num in nums {
        prefix += num;
        let mod_val = prefix % k;
        let current_max = mod_map.get(&mod_val).copied().unwrap_or(i64::MIN);
        let candidate = current_max + prefix;
        let new_dp = std::cmp::max(dp, candidate);
        let current_value = new_dp - prefix;

        if let Some(val) = mod_map.get_mut(&mod_val) {
            if current_value > *val {
                *val = current_value;
            }
        } else {
            mod_map.insert(mod_val, current_value);
        }

        dp = new_dp;
    }

    prefix - dp
}
